import React, { FunctionComponent, useState } from "react";
import { ctx } from "../services/Context";
import { Button, H1, H2, Icon } from "@blueprintjs/core";
import { observer } from "mobx-react";
import disconnect from "../images/logout_icon.png";
import { OurToaster } from "./OurToaster";
import { Intent } from "@blueprintjs/core/lib/esm/common/intent";
import { Pending } from "./Pending";

export const Connected: FunctionComponent = observer(() => {
  function logout(): void {
    ctx.store.setName("");
    ctx.store.setRole("");
    OurToaster.show({
      message: "Successfully disconnected.",
      intent: Intent.SUCCESS,
      timeout: 8000
    });
  }
  return (
    <div>
        <Button onClick={() => logout()}>
            <div className="fx -r center forbes">
                <img className="logout-icon" alt="disconnect" src={disconnect} />
                Disconnect
            </div>
        </Button>
      {ctx.store.getRole() === "client" ? (
        "client"
      ) : ctx.store.getRole() === "banker" ? (
        "banquier"
      ) : (
        <Pending />
      )}
    </div>
  );
});
